using UnityEngine;

public class PlayerController : MonoBehaviour
{
    [SerializeField] private PlayerInputRouter input;
    [SerializeField] private PlayerMotor2D motor;
    [SerializeField] private AbilityRouter abilities;

    private System.Action _onJumpPressed;
    private System.Action _onJumpReleased;
    private System.Action _onAbilityPressed;
    private System.Action _onAbilityReleased;
    private System.Action _onAttackPressed;
    private System.Action _onInteractPressed;

    private void Awake()
    {
        if (input == null) input = GetComponent<PlayerInputRouter>();
        if (motor == null) motor = GetComponent<PlayerMotor2D>();
        if (abilities == null) abilities = GetComponent<AbilityRouter>();

        // Tarefa #5: além de QueueJumpPressed/Released (salto normal), o
        // botão de Saltar agora também activa/termina o Glide genérico
        // (qualquer forma com canGlide) quando premido/largado no ar — ver
        // AbilityRouter.OnJumpPressedAirborne/OnJumpReleasedAirborne.
        _onJumpPressed = () =>
        {
            motor.QueueJumpPressed();
            abilities?.OnJumpPressedAirborne();
        };
        _onJumpReleased = () =>
        {
            motor.QueueJumpReleased();
            abilities?.OnJumpReleasedAirborne();
        };

        _onAbilityPressed = () => abilities?.OnAbilityPressed();
        _onAbilityReleased = () => abilities?.OnAbilityReleased();

        // P4: botão de ataque e botão de interagir (agarrar/escalar — sem botão dedicado).
        _onAttackPressed = () => abilities?.OnAttackPressed();
        _onInteractPressed = () => abilities?.OnInteractPressed();
    }

    private void OnEnable()
    {
        input.JumpPressed += _onJumpPressed;
        input.JumpReleased += _onJumpReleased;

        input.AbilityPressed += _onAbilityPressed;
        input.AbilityReleased += _onAbilityReleased;

        input.AttackPressed += _onAttackPressed;
        input.InteractPressed += _onInteractPressed;
    }

    private void OnDisable()
    {
        input.JumpPressed -= _onJumpPressed;
        input.JumpReleased -= _onJumpReleased;

        input.AbilityPressed -= _onAbilityPressed;
        input.AbilityReleased -= _onAbilityReleased;

        input.AttackPressed -= _onAttackPressed;
        input.InteractPressed -= _onInteractPressed;
    }

    private void Update()
    {
        motor.SetMoveX(input.Move.x);
    }
}
